	.TITLE	TZOOM15	.PROC	M680002	.REF	SM8	.REF	LIB	.REF	DRIVERS                       	.LOC	0OBUDIS:	.BLKB	30OBITMAP:.BLKB	10000LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LOAD.L	A4,A6	LOAD.W	D4,#LGVAR10$:	CLR.B	(A4+)	DEC.W	D4	JUMP,NE 10$	.W	LIB,?AFTIM	.B	NOCURS	.ASCII	"Abcdef...<CR>"	.ASCII	"Petit essai de zoom<CR>"	.ASCII	"01234546789<CR>"	.B	0	.EVEN	LOAD.L	A4,#(A6)+OBITMAP	LOAD.L	A3,#(A6)+OBUDIS	LOAD.W	(A3)+0,#DRAWRASTER	CLR.L	(A3)+2	CLR.L	(A3)+6	CLR.W	(A3)+10	CLR.L	(A3)+12	LOAD.L	(A3)+16,A4	LOAD.W	(A3)+20,#128/8	LOAD.W	(A3)+22,#128*2/3	LOAD.W	(A3)+24,#128*2/3	LOAD.B	(A3)+26,#SETDOT	LOAD.W	D3,#1+26	.W	LIB,?STRING	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	LOAD.L	A3,#(A6)+OBITMAP	LOAD.W	D3,#128	SWAP.W	D3	LOAD.W	D3,#128	CALL	ZOOM15	LOAD.L	A4,#(A6)+OBITMAP	LOAD.L	A3,#(A6)+OBUDIS	LOAD.W	(A3)+0,#DRAWRASTER	CLR.L	(A3)+2	LOAD.L	(A3)+6,A4	LOAD.W	(A3)+10,#128/8	CLR.L	(A3)+12	CLR.L	(A3)+16	CLR.W	(A3)+20	LOAD.W	(A3)+22,#128	LOAD.W	(A3)+24,#128	LOAD.B	(A3)+26,#SETDOT	LOAD.W	D3,#1+26	.W	LIB,?STRING	.W	LIB,?GETCAR	EXIT;--------\\; ZOOM15  >;========/; Agrandi dans un facteur 1.5 une image quelconque en mmoire.; L'image est cale en haut  gauche du bitmap.;	 Bitmap:;	|--------------------|----------|----> X;	|                    |          |;	|      image         |          |;	|      initiale      |          |;	|                  P0|          |;	|--------------------|          |;	|                               |;	|                             P1|;	|-------------------------------|;	|;	V  Y; in	A3.L	^bitmap;	D3.L	dimensions totales (dy;dx); out	-; mod	D7.WZOOM15:	PUSHM.L	D0..D4,A0..A4	LOAD.L	A4,A3		; A4 <-- ^bitmap	LOAD.W	D4,D3	ADD.W	D4,#8-1	SR.W	D4,#3		; D4 <-- Iy	LOAD.L	A2,#1		; A2 <-- Ix	LOAD.L	A3,#0	LOAD.W	A3,D4		; A3 <-- Iy	LOAD.W	D2,D3		; D2 <-- Dx	MUL.WU	D2,#2	DIV.WU	D2,#3		; D2 <-- Dx/1.5	SWAP.W	D3		; D3 <-- Dy	MUL.WU	D3,#2	DIV.WU	D3,#3		; D3 <-- Dy/1.5	LOAD.W	D0,D3	MUL.WU	D0,#3	DIV.WU	D0,#2	DEC.W	D0		; D0 <-- (Dy*1.5)-1	SWAP.W	D0	LOAD.W	D1,D2	MUL.WU	D1,#3	DIV.WU	D1,#2	LOAD.W	D0,D1	DEC.W	D0		; D0 <-- (Dx*1.5)-1	LOAD.L	A0,A4	CALL	GETAD0	LOAD.B	D1,D0	LOAD.L	A1,A0		; A1/D1 <-- P1 (coin inf/droite)	LOAD.W	D0,D3	DEC.W	D0		; D0 <-- Dy-1	SWAP.W	D0	LOAD.W	D0,D2	DEC.W	D0		; D0 <-- Dx-1	LOAD.L	A0,A4	CALL	GETAD0		; A0/D0 <-- P0 (coin inf/droite)	CALL	IMAGE15		; moteur ...	POPM.L	D0..D4,A0..A4	RET;--------\\; GETAD0  >;--------/; Calcul l'adresse du byte et le numro du bit.; in	D0.L	coordonne (y;x);	A0.L	^dbut bitmap;	A2	Ix;	A3	Iy; out	A0/D0	point (pointeur/bit); mod	A0/D0GETAD0:	PUSHM.L	D1,D2	LOAD.L	D1,D0	SWAP.W	D1	LOAD.W	D2,A3	MUL.WU	D1,D2	ADD.L	A0,D1		; A0 <-- ajoute offset pour Y	LOAD.W	D1,D0	SR.W	D1,#3	ADD.W	A0,D1		; A0 <-- ajoute offset pour X	NOT.B	D0	AND.B	D0,#B'111	; D0 <-- no du bit (0..7)	POPM.L	D1,D2	RET;--------------------\\; [INC,DEC][X,Y][0,1] >;--------------------/; Incrmente/dcrmente la position d'un point.; in	An/Dn	point;	A2	Ix;	A3	Iy; out	An/Dn	point; mod	An/Dn;INCX0:	.MACRO	INCX0	.LOCALMACRO FIN	DEC.B	D0	JUMP',NC FIN	LOAD.B	D0,#7	ADD.L	A0,A2FIN:	.ENDMACRO;DECX0:	.MACRO	DECX0	.LOCALMACRO FIN	INC.B	D0	COMP.B	D0,#8	JUMP',LO FIN	CLR.B	D0	SUB.L	A0,A2FIN:	.ENDMACRO;INCY0:	.MACRO	INCY0	ADD.L	A0,A3	.ENDMACRO;DECY0:	.MACRO	DECY0	SUB.L	A0,A3	.ENDMACRO;INCX1:	.MACRO	INCX1	.LOCALMACRO FIN	DEC.B	D1	JUMP',NC FIN	LOAD.B	D1,#7	ADD.L	A1,A2FIN:	.ENDMACRO;DECX1:	.MACRO	DECX1	.LOCALMACRO FIN	INC.B	D1	COMP.B	D1,#8	JUMP',LO FIN	CLR.B	D1	SUB.L	A1,A2FIN:	.ENDMACRO;INCY1:	.MACRO	INCY1	ADD.L	A1,A3	.ENDMACRO;DECY1:	.MACRO	DECY1	SUB.L	A1,A3	.ENDMACRO;--------\\; IMAGE15 >;--------/; Agrandi de 1.5 toute une image.; in	A0/D0	point source;	A1/D1	point destination;	A2	Ix;	A3	Iy;	D2.W	Dx;	D3.W	Dy; out	-; mod	-IMAGE15:	PUSHM.L	D0..D3,A0,A110$:	CALL	LIGNE1	DECY0	DECY1	DEC.W	D3	JUMP',EQ 90$	CALL	LIGNE2	DECY0	DECY1	DECY1	DEC.W	D3	JUMP,NE 10$90$:	POPM.L	D0..D3,A0,A1	RET;--------\\; LIGNE1  >;--------/; Double toute une ligne.; in	A0/D0	point source;	A1/D1	point destination;	A2	Ix;	A3	Iy;	D2.W	Dx; out	-; mod	-LIGNE1:	PUSHM.L	D0..D2,A0,A110$:	TEST.B	(A0):D0	JUMP',BC 20$	TSET.B	(A1):D1	JUMP'	25$20$:	TCLR.B	(A1):D125$:	DECX0	DECX1	DEC.W	D2	JUMP',EQ 90$	TEST.B	(A0):D0	JUMP',BC 50$	TSET.B	(A1):D1	DECX0	DECX1	TEST.B	(A0):D0	JUMP',BC 40$	TSET.B	(A1):D1	JUMP'	60$40$:	TCLR.B	(A1):D1	JUMP'	60$50$:	DECX0	TCLR.B	(A1):D1	DECX1	TCLR.B	(A1):D160$:	DECX1	DEC.W	D2	JUMP,NE 10$90$:	POPM.L	D0..D2,A0,A1	RET;--------\\; LIGNE2  >;--------/; Double toute une ligne.; in	A0/D0	point source;	A1/D1	point destination;	A2	Ix;	A3	Iy;	D2.W	Dx; out	-; mod	-LIGNE2:	PUSHM.L	D0..D2,A0,A110$:	TEST.B	(A0):D0	JUMP',BC 30$	TSET.B	(A1):D1	DECY0	DECY1	TEST.B	(A0):D0	JUMP',BC 20$	TSET.B	(A1):D1	INCY0	INCY1	JUMP'	40$20$:	TCLR.B	(A1):D1	INCY0	INCY1	JUMP'	40$30$:	TCLR.B	(A1):D1	DECY1	TCLR.B	(A1):D1	INCY140$:	DECX0	DECX1	DEC.W	D2	JUMP',EQ 90$	TEST.B	(A0):D0	JUMP',BC 80$	TSET.B	(A1):D1	DECY0	DECY1	TEST.B	(A0):D0	JUMP',BC 50$	TSET.B	(A1):D1	JUMP'	55$50$:	TCLR.B	(A1):D155$:	DECX0	DECX1	TEST.B	(A0):D0	JUMP',BC 60$	TSET.B	(A1):D1	JUMP'	65$60$:	TCLR.B	(A1):D165$:	INCY0	INCY1	TEST.B	(A0):D0	JUMP',BC 70$	TSET.B	(A1):D1	JUMP'	85$70$:	TCLR.B	(A1):D1	JUMP'	85$80$:	DECX0	TCLR.B	(A1):D1	DECY1	TCLR.B	(A1):D1	DECX1	TCLR.B	(A1):D1	INCY1	TCLR.B	(A1):D185$:	DECX1	DEC.W	D2	JUMP,NE 10$90$:	POPM.L	D0..D2,A0,A1	RETVAR:	.FILLB	LGVAR,0	.END	START